import org.springframework.beans.BeansException;
import org.springframework.beans.factory.config.BeanDefinition;
import org.springframework.beans.factory.support.BeanDefinitionRegistry;
import org.springframework.beans.factory.support.BeanDefinitionRegistryPostProcessor;
import org.springframework.beans.factory.support.GenericBeanDefinition;
import org.springframework.context.annotation.Configuration;

@Configuration
public class MyBeanFactoryPostProcessor implements BeanDefinitionRegistryPostProcessor {

    @Override
    public void postProcessBeanDefinitionRegistry(BeanDefinitionRegistry registry) throws BeansException {
        // 创建一个新的GenericBeanDefinition来定义一个需要动态注册的Bean
        GenericBeanDefinition beanDefinition = new GenericBeanDefinition();
        beanDefinition.setBeanClass(MyPrototypeBeanClass.class); // 设置Bean的类类型
        beanDefinition.setScope(BeanDefinition.SCOPE_PROTOTYPE); // 设置为多例

        // 将新的Bean定义注册到Spring容器中
        registry.registerBeanDefinition("myDynamicPrototypeBean", beanDefinition);
    }

    @Override
    public void postProcessBeanFactory(ConfigurableListableBeanFactory beanFactory) throws BeansException {
        // 这里可以进行其他的beanFactory级别的修改调整
    }
}
```

